// export default Navigation
import React, { useState, useRef } from 'react';
import styled from 'styled-components';
import avatarDefault from '../../img/avatar.png';
import { signout } from '../../utils/Icons';
import { menuItems } from '../../utils/menuItems';
import { Link } from 'react-router-dom';
import axios from 'axios';

function Navigation({ active, setActive, user }) {
    const [avatar, setAvatar] = useState(user?.profilePicUrl || avatarDefault);
    const fileInputRef = useRef(null);

    const handleAvatarClick = () => {
        fileInputRef.current.click();
    };

    const handleFileChange = async (e) => {
        const file = e.target.files[0];
        if (!file) return;

        const formData = new FormData();
        formData.append('file', file);
        formData.append('userId', user._id); // assuming user object is passed as prop

        try {
            const res = await axios.post('/api/upload-profile-pic', formData);
            setAvatar(res.data.imageUrl);
        } catch (err) {
            console.error('Upload failed', err);
        }
    };

    return (
        <NavStyled>
            <div className="user-con">
                <input
                    type="file"
                    ref={fileInputRef}
                    onChange={handleFileChange}
                    style={{ display: 'none' }}
                    accept="image/*"
                />
                <img src={avatar} alt="Profile" onClick={handleAvatarClick} title="Click to change picture" />
                <div className="text">
                    <h2>{user?.name || 'User'}</h2>
                    <p>Your Money</p>
                </div>
            </div>
            <ul className="menu-items">
                {menuItems.map((item) => {
                    return (
                        <li
                            key={item.id}
                            onClick={() => setActive(item.id)}
                            className={active === item.id ? 'active' : ''}
                        >
                            {item.icon}
                            <span>{item.title}</span>
                        </li>
                    );
                })}
            </ul>
            <div className="bottom-nav">
                <Link to="/">
                    <li>
                        {signout} Sign Out
                    </li>
                </Link>
            </div>
        </NavStyled>
    );
}

